import type { ForwardRefExoticComponent, ReactElement } from 'react';

const REACT_FORWARD_REF_TYPE = Symbol.for('react.forward_ref');

/**
 * Проверяет, является ли значение компонентом, обёрнутым в React.forwardRef().
 * Важно: передавать компонент (type элемента), а не сам элемент — у элемента
 * $$typeof === Symbol(react.element), у forwardRef-компонента === Symbol(react.forward_ref).
 */
export const isForwardRef = (component: unknown): component is ForwardRefExoticComponent<any> => {
	return (
		component !== null &&
		typeof component === 'object' &&
		'$$typeof' in component &&
		(component as { $$typeof?: symbol }).$$typeof === REACT_FORWARD_REF_TYPE
	);
};

type ElementWithRef = ReactElement & { ref?: unknown };

/**
 * Проверяет, может ли переданный React-элемент получать ref: либо у него тип forwardRef,
 * либо вызывающий код уже передал ref в props.
 */
export const isElementAcceptingRef = (element: ReactElement): boolean => {
	return isForwardRef(element.type) || (element as ElementWithRef).ref != null;
};
